from jinja2 import Environment

class FakeTranslations:
    def gettext(self, s):
        return s
    def ngettext(self, s, p, n):
        return s if n == 1 else p
    def dgettext(self, domain, s):
        return f'[{domain}] {s}'
    def dngettext(self, domain, s, p, n):
        return f'[{domain}] ' + (s if n == 1 else p)

env = Environment(extensions=['jinja2.ext.i18n'])
env.install_gettext_translations(FakeTranslations())
t = env.from_string('{% trans domain=\"admin\" %}Hello{% endtrans %}')
print(t.render())

t2 = env.from_string('{% trans count, domain=\"admin\" %}{{ count }} item{% pluralize %}{{ count }} items{% endtrans %}')
print(t2.render(count=1))
print(t2.render(count=5))

# newstyle
env2 = Environment(extensions=['jinja2.ext.i18n'])
env2.install_gettext_translations(FakeTranslations(), newstyle=True)
t3 = env2.from_string('{% trans domain=\"admin\" %}Hello {{ name }}{% endtrans %}')
print(t3.render(name='World'))

# fallback: translations w/o dgettext, newstyle
class Plain:
    def gettext(self, s):
        return s.upper()
    def ngettext(self, s, p, n):
        return (s if n==1 else p).upper()

